{
  "name": "BizAuto - Universal Business Automation",
  "description": "A comprehensive SaaS platform for business automation including online booking, electronic journals, client management, inventory tracking, payroll calculation, and financial analytics."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppSection {
  DASHBOARD = 'DASHBOARD',
  BOOKING_JOURNAL = 'BOOKING_JOURNAL',
  CLIENTS = 'CLIENTS',
  INVENTORY = 'INVENTORY',
  FINANCE = 'FINANCE',
  ANALYTICS = 'ANALYTICS',
  LOYALTY = 'LOYALTY',
  PAYROLL = 'PAYROLL',
  NOTIFICATIONS = 'NOTIFICATIONS',
  NETWORK = 'NETWORK',
  INTEGRATIONS = 'INTEGRATIONS',
  AI_ASSISTANT = 'AI_ASSISTANT'
}

export interface Client {
  id: string;
  name: string;
  phone: string;
  email: string;
  lastVisit: string;
  totalSpent: number;
}

export interface Appointment {
  id: string;
  clientId: string;
  clientName: string;
  service: string;
  startTime: string;
  duration: number;
  status: 'confirmed' | 'pending' | 'cancelled';
  price: number;
}

export interface InventoryItem {
  id: string;
  name: string;
  stock: number;
  minStock: number;
  category: string;
  price: number;
}

import React, { useState } from 'react';
import { AppSection } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import BookingJournal from './components/BookingJournal';
import ClientManagement from './components/ClientManagement';
import InventoryManager from './components/InventoryManager';
import FinancialStats from './components/FinancialStats';
import AnalyticsView from './components/AnalyticsView';
import PayrollCalculator from './components/PayrollCalculator';
import AIAssistant from './components/AIAssistant';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.DASHBOARD);

  const renderContent = () => {
    switch (activeSection) {
      case AppSection.DASHBOARD:
        return <Dashboard />;
      case AppSection.BOOKING_JOURNAL:
        return <BookingJournal />;
      case AppSection.CLIENTS:
        return <ClientManagement />;
      case AppSection.INVENTORY:
        return <InventoryManager />;
      case AppSection.FINANCE:
        return <FinancialStats />;
      case AppSection.ANALYTICS:
        return <AnalyticsView />;
      case AppSection.PAYROLL:
        return <PayrollCalculator />;
      case AppSection.AI_ASSISTANT:
        return <AIAssistant />;
      default:
        return (
          <div className="p-8 text-center bg-white rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-2xl font-bold text-slate-800 mb-4">Under Development</h2>
            <p className="text-slate-600">The module for <strong>{activeSection}</strong> is coming soon.</p>
          </div>
        );
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeSection={activeSection} onSectionChange={setActiveSection} />
      <div className="flex-1 flex flex-col min-w-0">
        <Header activeSection={activeSection} />
        <main className="flex-1 p-6 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

