import React, { useState } from 'react';
import { Send, Sparkles, BrainCircuit, Lightbulb, LineChart } from 'lucide-react';
import { GoogleGenAI } from '@google/genai';

const AIAssistant: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'ai', content: string }[]>([
    { role: 'ai', content: 'Привет! Я ваш умный помощник. Я могу проанализировать ваши финансовые показатели, предложить план развития или помочь составить график сотрудников. Что вы хотите обсудить сегодня?' }
  ]);
  const [isLoading, setIsLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMessage,
        config: {
          systemInstruction: 'You are an expert business consultant for a small to medium enterprise (SME). You analyze sales data, customer retention, and operations. Provide concise, actionable advice in Russian.',
        }
      });

      setMessages(prev => [...prev, { role: 'ai', content: response.text || "Извините, я не смог сформировать ответ. Попробуйте еще раз." }]);
    } catch (error) {
      console.error('AI Error:', error);
      setMessages(prev => [...prev, { role: 'ai', content: "Произошла ошибка при обращении к AI. Убедитесь, что API ключ настроен правильно." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-10rem)] bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
      <div className="p-6 bg-gradient-to-r from-purple-600 to-indigo-600 text-white flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center backdrop-blur-md">
            <Sparkles size={20} />
          </div>
          <div>
            <h3 className="font-bold">BizAuto Smart Assistant</h3>
            <p className="text-xs text-purple-100">Искусственный интеллект для вашего бизнеса</p>
          </div>
        </div>
        <div className="hidden md:flex gap-2">
          <div className="px-3 py-1 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-wider">GPT-4 Turbo Class</div>
          <div className="px-3 py-1 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-wider">Live Analysis</div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? 'bg-orange-500 text-white rounded-tr-none' 
                : 'bg-white border border-slate-100 text-slate-800 rounded-tl-none'
            }`}>
              <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.content}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl rounded-tl-none shadow-sm flex items-center gap-2">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-purple-500 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-purple-500 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-purple-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
              <span className="text-xs text-slate-400 font-medium">Анализирую данные...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-slate-100 bg-white">
        <div className="max-w-4xl mx-auto space-y-4">
          <div className="grid grid-cols-3 gap-2">
            <button 
              onClick={() => setInput('Проанализируй выручку за последний месяц и дай прогноз')}
              className="flex items-center gap-2 p-2 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-bold text-slate-600 transition-all border border-slate-100"
            >
              <LineChart size={14} className="text-purple-500" /> АНАЛИЗ ВЫРУЧКИ
            </button>
            <button 
              onClick={() => setInput('Как увеличить количество повторных визитов клиентов?')}
              className="flex items-center gap-2 p-2 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-bold text-slate-600 transition-all border border-slate-100"
            >
              <BrainCircuit size={14} className="text-indigo-500" /> СТРАТЕГИЯ Retention
            </button>
            <button 
              onClick={() => setInput('Предложи идеи для программы лояльности')}
              className="flex items-center gap-2 p-2 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-bold text-slate-600 transition-all border border-slate-100"
            >
              <Lightbulb size={14} className="text-amber-500" /> ИДЕИ ЛОЯЛЬНОСТИ
            </button>
          </div>
          <div className="relative">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Спросите AI о чем угодно..." 
              className="w-full pl-4 pr-12 py-3.5 bg-slate-100 border-none rounded-2xl text-sm focus:outline-none focus:ring-2 focus:ring-purple-500/20 transition-all"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-purple-600 text-white rounded-xl hover:bg-purple-700 transition-all disabled:opacity-50"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AIAssistant;

export enum AppSection {
  DASHBOARD = 'DASHBOARD',
  BOOKING_JOURNAL = 'BOOKING_JOURNAL',
  CLIENTS = 'CLIENTS',
  STAFF = 'STAFF',
  INVENTORY = 'INVENTORY',
  FINANCE = 'FINANCE',
  ANALYTICS = 'ANALYTICS',
  LOYALTY = 'LOYALTY',
  PAYROLL = 'PAYROLL',
  NOTIFICATIONS = 'NOTIFICATIONS',
  INTEGRATIONS = 'INTEGRATIONS'
}

export interface Client {
  id: string;
  name: string;
  phone: string;
  email: string;
  visits: number;
  totalSpent: number;
  lastVisit: string;
  status: 'VIP' | 'Active' | 'New' | 'Passive';
