};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { AppSection, Client, Staff, Appointment } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import BookingJournal from './components/BookingJournal';
import ClientManagement from './components/ClientManagement';
import StaffManagement from './components/StaffManagement';
import InventoryManager from './components/InventoryManager';
import FinancialStats from './components/FinancialStats';
import AnalyticsView from './components/AnalyticsView';
import PayrollCalculator from './components/PayrollCalculator';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.DASHBOARD);

  // Persistence using local storage for demo purposes
  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('biz_clients');
    return saved ? JSON.parse(saved) : [];
  });

  const [staff, setStaff] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('biz_staff');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Александр Мастеров', role: 'Топ-мастер', specialization: 'Стрижки', color: 'orange' },
      { id: '2', name: 'Мария Стилистова', role: 'Стилист', specialization: 'Окрашивание', color: 'blue' }
    ];
  });

  const [appointments, setAppointments] = useState<Appointment[]>(() => {
    const saved = localStorage.getItem('biz_appointments');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('biz_clients', JSON.stringify(clients));
  }, [clients]);

  useEffect(() => {
    localStorage.setItem('biz_staff', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    localStorage.setItem('biz_appointments', JSON.stringify(appointments));
  }, [appointments]);

  const renderContent = () => {
    switch (activeSection) {
      case AppSection.DASHBOARD:
        return <Dashboard />;
      case AppSection.BOOKING_JOURNAL:
        return <BookingJournal 
                  appointments={appointments} 
                  staff={staff} 
                  clients={clients}
                  onUpdateAppointments={setAppointments} 
                />;
      case AppSection.CLIENTS:
        return <ClientManagement clients={clients} onUpdateClients={setClients} />;
      case AppSection.STAFF:
        return <StaffManagement staff={staff} onUpdateStaff={setStaff} />;
      case AppSection.INVENTORY:
        return <InventoryManager />;
      case AppSection.FINANCE:
        return <FinancialStats />;
      case AppSection.ANALYTICS:
        return <AnalyticsView />;
      case AppSection.PAYROLL:
        return <PayrollCalculator />;
      default:
        return (
          <div className="p-8 text-center bg-white rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-2xl font-bold text-slate-800 mb-4">Раздел в разработке</h2>
            <p className="text-slate-600">Модуль <strong>{activeSection}</strong> будет доступен в ближайшем обновлении.</p>
          </div>
        );
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeSection={activeSection} onSectionChange={setActiveSection} />
      <div className="flex-1 flex flex-col min-w-0">
        <Header activeSection={activeSection} />
        <main className="flex-1 p-6 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, Plus, X, Clock, User, Scissors } from 'lucide-react';
import { Appointment, Staff, Client } from '../types';

interface BookingJournalProps {
  appointments: Appointment[];
  staff: Staff[];
  clients: Client[];
  onUpdateAppointments: (apps: Appointment[]) => void;
}

const BookingJournal: React.FC<BookingJournalProps> = ({ appointments, staff, clients, onUpdateAppointments }) => {
  const [selectedStaffId, setSelectedStaffId] = useState<string>(staff[0]?.id || '');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);

  const hours = Array.from({ length: 13 }, (_, i) => `${9 + i}:00`);
  const currentDate = new Date().toISOString().split('T')[0];

  const handleSave = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const newApp: Appointment = {
      id: editingAppointment?.id || Math.random().toString(36).substr(2, 9),
      clientId: formData.get('clientId') as string,
      clientName: clients.find(c => c.id === formData.get('clientId'))?.name || 'Неизвестный клиент',
      staffId: selectedStaffId,
      service: formData.get('service') as string,
      startTime: formData.get('startTime') as string,
      date: currentDate,
      duration: parseInt(formData.get('duration') as string),
      status: formData.get('status') as any,
      price: parseInt(formData.get('price') as string),
    };

    if (editingAppointment) {
      onUpdateAppointments(appointments.map(a => a.id === editingAppointment.id ? newApp : a));
    } else {
      onUpdateAppointments([...appointments, newApp]);
    }

    setIsModalOpen(false);
    setEditingAppointment(null);
  };

  const deleteAppointment = (id: string) => {
    if (confirm('Удалить эту запись?')) {
      onUpdateAppointments(appointments.filter(a => a.id !== id));
      setIsModalOpen(false);
      setEditingAppointment(null);
    }
  };

  const getSlotPosition = (time: string) => {
    const [h, m] = time.split(':').map(Number);
    const startH = 9;
    const pixelsPerHour = 80;
    return (h - startH) * pixelsPerHour + (m / 60) * pixelsPerHour;
  };

  const staffAppointments = appointments.filter(a => a.staffId === selectedStaffId && a.date === currentDate);

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm flex flex-col h-[calc(100vh-10rem)] relative">
      {/* Header Controls */}
      <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-white sticky top-0 z-10 rounded-t-2xl">
        <div className="flex items-center gap-4">
          <div className="flex items-center bg-slate-50 rounded-lg p-1 border border-slate-200">
            <button className="p-1.5 hover:bg-white hover:shadow-sm rounded-md"><ChevronLeft size={18}/></button>
            <span className="px-4 text-sm font-semibold text-slate-700">Сегодня, {new Date().toLocaleDateString('ru-RU')}</span>
            <button className="p-1.5 hover:bg-white hover:shadow-sm rounded-md"><ChevronRight size={18}/></button>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
            {staff.map(s => (
              <button
                key={s.id}
                onClick={() => setSelectedStaffId(s.id)}
                className={`px-4 py-2 text-xs font-semibold rounded-lg transition-all ${selectedStaffId === s.id ? 'bg-white shadow-sm text-orange-600' : 'text-slate-500 hover:text-slate-700'}`}
              >
                {s.name.split(' ')[0]}
              </button>
            ))}
          </div>
          <button 
            onClick={() => { setEditingAppointment(null); setIsModalOpen(true); }}
            className="flex items-center gap-2 bg-orange-500 text-white px-4 py-2 rounded-xl text-sm font-bold shadow-lg shadow-orange-100 hover:bg-orange-600 transition-all"
          >
            <Plus size={18} /> Добавить запись
          </button>
        </div>
      </div>

      {/* Calendar Grid */}
      <div className="flex-1 overflow-auto p-4 bg-slate-50/30">
        <div className="grid grid-cols-[80px_1fr] gap-4 relative min-h-[1040px]">
          <div className="space-y-[68px] mt-2">
            {hours.map(h => (
              <div key={h} className="text-xs font-bold text-slate-400 text-right pr-4 h-3">{h}</div>
            ))}
          </div>

          <div className="relative border-l border-slate-200 bg-white shadow-inner rounded-lg overflow-hidden">
            {hours.map((_, i) => (
              <div key={i} className="h-20 border-b border-slate-100 border-dashed"></div>
            ))}

            {staffAppointments.map(app => (
              <div 
                key={app.id}
                onClick={() => { setEditingAppointment(app); setIsModalOpen(true); }}
                style={{ 
                  top: `${getSlotPosition(app.startTime)}px`, 
                  height: `${(app.duration / 60) * 80}px` 
                }}
                className={`absolute left-2 right-2 p-3 rounded-xl border-l-4 shadow-sm cursor-pointer transition-all hover:brightness-95 z-0 ${
                  app.status === 'confirmed' ? 'bg-emerald-50 border-emerald-500 text-emerald-900' :
                  app.status === 'cancelled' ? 'bg-slate-50 border-slate-400 text-slate-600' :
                  'bg-orange-50 border-orange-500 text-orange-900'
                }`}
              >
                <div className="flex justify-between items-start">
                  <span className="text-xs font-black truncate">{app.clientName}</span>
                  <span className="text-[10px] font-bold opacity-70">{app.startTime}</span>
                </div>
                <p className="text-[10px] font-medium truncate mt-1">{app.service}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Modal for Add/Edit */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-in zoom-in duration-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">
                {editingAppointment ? 'Редактировать запись' : 'Новая запись'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600"><X/></button>
            </div>
            <form onSubmit={handleSave} className="p-6 space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Клиент</label>
                <div className="relative">
                  <User className="absolute left-3 top-3 text-slate-400" size={16} />
                  <select 
                    name="clientId" 
                    defaultValue={editingAppointment?.clientId}
                    className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-orange-500/20"
                    required
                  >
                    <option value="">Выберите клиента</option>
                    {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Время</label>
                  <div className="relative">
                    <Clock className="absolute left-3 top-3 text-slate-400" size={16} />
                    <input name="startTime" type="time" defaultValue={editingAppointment?.startTime || '09:00'} className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm" required />
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Длительность (мин)</label>
                  <input name="duration" type="number" defaultValue={editingAppointment?.duration || 60} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm" required />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Услуга</label>
                <div className="relative">
                  <Scissors className="absolute left-3 top-3 text-slate-400" size={16} />
                  <input name="service" type="text" defaultValue={editingAppointment?.service} placeholder="Например: Стрижка" className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm" required />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Стоимость</label>
                  <input name="price" type="number" defaultValue={editingAppointment?.price || 0} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm" required />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Статус</label>
                  <select name="status" defaultValue={editingAppointment?.status || 'pending'} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm">
                    <option value="pending">Ожидание</option>
                    <option value="confirmed">Подтверждено</option>
                    <option value="cancelled">Отменено</option>
                  </select>
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                {editingAppointment && (
                  <button 
                    type="button"
                    onClick={() => deleteAppointment(editingAppointment.id)}
                    className="flex-1 py-3 border border-red-200 text-red-600 rounded-xl font-bold text-sm hover:bg-red-50 transition-all"
                  >
                    Удалить
                  </button>
                )}
                <button type="submit" className="flex-[2] py-3 bg-slate-900 text-white rounded-xl font-bold text-sm hover:bg-slate-800 transition-all">
                  {editingAppointment ? 'Сохранить изменения' : 'Создать запись'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BookingJournal;

import React, { useState } from 'react';
import { UserPlus, Briefcase, Trash2, ShieldCheck, X } from 'lucide-react';
import { Staff } from '../types';

interface StaffManagementProps {
  staff: Staff[];
  onUpdateStaff: (staff: Staff[]) => void;
}

const StaffManagement: React.FC<StaffManagementProps> = ({ staff, onUpdateStaff }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handleAddStaff = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const colors = ['orange', 'blue', 'emerald', 'purple', 'rose', 'amber'];
    const newStaff: Staff = {
      id: Math.random().toString(36).substr(2, 9),
      name: formData.get('name') as string,
      role: formData.get('role') as string,
      specialization: formData.get('specialization') as string,
      color: colors[staff.length % colors.length]
    };
    onUpdateStaff([...staff, newStaff]);
    setIsModalOpen(false);
  };

  const removeStaff = (id: string) => {
    if (confirm('Удалить сотрудника из системы?')) {
      onUpdateStaff(staff.filter(s => s.id !== id));
