        >
          <UserPlus size={18} />
          <span>Добавить сотрудника</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {staff.map((member) => (
          <div key={member.id} className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm relative group transition-all hover:shadow-md">
            <button 
              onClick={() => removeStaff(member.id)}
              className="absolute top-4 right-4 p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
            >
              <Trash2 size={16} />
            </button>
            <div className="flex items-center gap-4 mb-6">
              <div className={`w-14 h-14 rounded-2xl bg-${member.color}-100 flex items-center justify-center text-${member.color}-600 font-black text-xl shadow-inner`}>
                {member.name.charAt(0)}
              </div>
              <div>
                <h4 className="font-bold text-slate-900 leading-tight">{member.name}</h4>
                <div className="flex items-center gap-1.5 mt-1">
                  <ShieldCheck size={12} className="text-emerald-500" />
