  const [staff, setStaff] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('biz_staff');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Александр Мастеров', role: 'Топ-мастер', specialization: 'Стрижки', color: 'orange' },
      { id: '2', name: 'Мария Стилистова', role: 'Стилист', specialization: 'Окрашивание', color: 'blue' }
