import NotificationCenter from './components/NotificationCenter';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.DASHBOARD);

  // Dynamic states with localStorage
  const [clients, setClients] = useState<Client[]>(() => JSON.parse(localStorage.getItem('b_clients') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(() => JSON.parse(localStorage.getItem('b_staff') || '[]'));
  const [appointments, setAppointments] = useState<Appointment[]>(() => JSON.parse(localStorage.getItem('b_appointments') || '[]'));
  const [inventory, setInventory] = useState<Product[]>(() => JSON.parse(localStorage.getItem('b_inventory') || '[]'));

  useEffect(() => localStorage.setItem('b_clients', JSON.stringify(clients)), [clients]);
  useEffect(() => localStorage.setItem('b_staff', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('b_appointments', JSON.stringify(appointments)), [appointments]);
  useEffect(() => localStorage.setItem('b_inventory', JSON.stringify(inventory)), [inventory]);

  const renderContent = () => {
    switch (activeSection) {
      case AppSection.DASHBOARD: return <Dashboard clients={clients} appointments={appointments} />;
      case AppSection.BOOKING_JOURNAL: return <BookingJournal appointments={appointments} staff={staff} clients={clients} onUpdateAppointments={setAppointments} />;
      case AppSection.CLIENTS: return <ClientManagement clients={clients} onUpdateClients={setClients} />;
      case AppSection.STAFF: return <StaffManagement staff={staff} onUpdateStaff={setStaff} />;
      case AppSection.INVENTORY: return <InventoryManager inventory={inventory} onUpdateInventory={setInventory} />;
      case AppSection.FINANCE: return <FinancialStats appointments={appointments} />;
      case AppSection.LOYALTY: return <LoyaltyManager clients={clients} onUpdateClients={setClients} />;
      case AppSection.NOTIFICATIONS: return <NotificationCenter />;
      default: return (
        <div className="flex flex-col items-center justify-center h-full opacity-50">
          <h2 className="header-font text-2xl font-bold">In Development</h2>
          <p>This module is being fine-tuned for performance.</p>
        </div>
      );
    }
  };

  return (
    <div className="flex min-h-screen bg-[#0a0a0a] text-slate-300 font-sans selection:bg-blue-600/30">
      <Sidebar activeSection={activeSection} onSectionChange={setActiveSection} />
      <div className="flex-1 flex flex-col min-w-0">
        <Header activeSection={activeSection} />
        <main className="flex-1 p-8 overflow-y-auto">
          <div className="max-w-7xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-700">
            {renderContent()}
          </div>
        </main>
      </div>
    </div>
  );
};

