          </div>
        )) : (
          <div className="lg:col-span-3 py-32 text-center opacity-20">
             <UserPlus size={64} className="mx-auto mb-6" />
             <p className="header-font text-xl font-bold uppercase tracking-[0.4em]">Team is currently empty</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="glass-panel w-full max-w-md rounded-[2.5rem] border border-white/10 p-10">
            <div className="flex justify-between items-center mb-10">
              <h3 className="header-font text-xl font-black">Contract New Expert</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-500 hover:text-white"><X/></button>
            </div>
            <form onSubmit={handleAddStaff} className="space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase">Полное имя</label>
                <input name="name" type="text" className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white outline-none focus:border-blue-500" required />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase">Должность</label>
                <select name="role" className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white outline-none focus:border-blue-500" required>
                  <option className="bg-[#111]" value="Lead Engineer">Lead Engineer</option>
                  <option className="bg-[#111]" value="Technical Specialist">Technical Specialist</option>
                  <option className="bg-[#111]" value="Operations Manager">Operations Manager</option>
                  <option className="bg-[#111]" value="Junior Associate">Junior Associate</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase">Специализация</label>
                <input name="specialization" type="text" className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white outline-none focus:border-blue-500" required />
              </div>
              <button type="submit" className="w-full bugatti-gradient py-5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-blue-900/20">Подписать контракт</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

